import json
with open(r'C:\Users\0000250059\AppData\Local\Packages\TheBrowserCompany.Arc_ttt1ap7aakyb4\LocalCache\Local\Arc\User Data\Default\Bookmarks', 'r', encoding='utf-8') as f:
    data = json.load(f)
print('Top keys:', list(data.keys()))
roots = data.get('roots', {})
print('Roots keys:', list(roots.keys()))
def count_bookmarks(node, depth=0):
    results = []
    if node.get('type') == 'url':
        results.append((node.get('name',''), node.get('url','')))
    for child in node.get('children', []):
        results.extend(count_bookmarks(child, depth+1))
    return results
for rk in roots:
    if isinstance(roots[rk], dict):
        bm = count_bookmarks(roots[rk])
        print(f'  {rk}: {len(bm)} bookmarks')
        for name, url in bm[:5]:
            print(f'    - {name[:50]} | {url[:80]}')
        if len(bm) > 5:
            print(f'    ... and {len(bm)-5} more')
